SELECT SUM(employed) AS total_employed, AVG(unemployment_rate) AS average_unemployment_rate
FROM employment_data
WHERE gender = 'Male' AND age_group = '18-24' AND region_id = 1;

SELECT * FROM employment_data
WHERE unemployment_rate > 5.0
ORDER BY date DESC;

SELECT data_id, region_id, date, unemployment_rate, labour_participation_rate
FROM employment_data
WHERE unemployment_rate > (
    SELECT AVG(unemployment_rate)
    FROM employment_data
);

SELECT COUNT(DISTINCT u.email) AS unique_users
FROM users u
JOIN employment_data ed ON u.user_id = ed.source_id;
